1	const PROCESSING_FEE = 5;
2	const FIRST_INSURANCE_RATE = 0.1;
3	
4	const BASE_PREMIUMS: Record<string, number> = {
5	  sword: 100,
6	  amulet: 60,
7	  staff: 80,
8	  potion: 40,
9	  rune: 25,
10	};
11	
12	const COMPONENT_TYPES = new Set(["rune"]);
13	const BLOCK_SIZE = 3;
14	const BLOCK_PREMIUM = 60;
15	
16	function calculateQuotePremium(items: Array<{ type: string }>): number {
17	  const counts: Record<string, number> = {};
18	  for (const item of items) {
19	    counts[item.type] = (counts[item.type] ?? 0) + 1;
20	  }
21	
22	  let policyBasePremium = 0;
23	  for (const [type, count] of Object.entries(counts)) {
24	    if (COMPONENT_TYPES.has(type) && count === BLOCK_SIZE) {
25	      policyBasePremium += BLOCK_PREMIUM;
26	    } else {
27	      policyBasePremium += count * (BASE_PREMIUMS[type] ?? 0);
28	    }
29	  }
30	
31	  const firstInsuranceSurcharge = policyBasePremium * FIRST_INSURANCE_RATE;
32	  return policyBasePremium + firstInsuranceSurcharge + PROCESSING_FEE;
33	}
34	
35	interface QuoteResult {
36	  premium: number;
37	}
38	
39	interface ScenarioOutcome {
40	  results: QuoteResult[];
41	}
42	
43	export function processScenario(scenario: {
44	  customer: { yearsWithMHPCO: number };
45	  steps: Array<{ op: string; items?: Array<{ type: string }> }>;
46	}): ScenarioOutcome {
47	  return {
48	    results: scenario.steps.map((step) => ({
49	      premium: calculateQuotePremium(step.items ?? []),
50	    })),
51	  };
52	}
